import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as l,e as a}from"./app-76561525.js";const r={},t=a('<p>简单介绍长连接与短连接的优缺点。</p><h2 id="短连接" tabindex="-1"><a class="header-anchor" href="#短连接" aria-hidden="true">#</a> 短连接</h2><figure><img src="https://img.bookandmusic.cn/blog/2022/01/LYVCBY.png" alt="LYVCBY" tabindex="0" loading="lazy"><figcaption>LYVCBY</figcaption></figure><ol><li>client 向 server 发起连接请求</li><li>server 接到请求，双方建立连接</li><li>client 向 server 发送消息</li><li>server 回应 client</li><li>一次读写完成，此时双方任何一个都可以发起 close 操作</li></ol><h2 id="长连接" tabindex="-1"><a class="header-anchor" href="#长连接" aria-hidden="true">#</a> 长连接</h2><figure><img src="https://img.bookandmusic.cn/blog/2022/01/tDUwvB.png" alt="tDUwvB" tabindex="0" loading="lazy"><figcaption>tDUwvB</figcaption></figure><ol><li>client 向 server 发起连接</li><li>server 接到请求，双方建立连接</li><li>client 向 server 发送消息</li><li>server 回应 client</li><li>一次读写完成，连接不关闭</li><li>后续读写操作…</li><li>长时间操作之后 client 发起关闭请求</li></ol><h2 id="优缺点分析" tabindex="-1"><a class="header-anchor" href="#优缺点分析" aria-hidden="true">#</a> 优缺点分析</h2><ol><li><p>长连接可以省去较多的 TCP 建立和关闭的操作，节约时间。但是如果用户量太大容易造成服务器负载过高最终导致服务不可用</p></li><li><p>短连接对于服务器来说实现起来较为简单，存在的连接都是有用的连接，不需要额外的控制手段。但是如果用户访问量很大, 往往可能在很短时间内需要创建大量的连接，造成服务器响应速度过慢</p></li></ol><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><ol><li><p>小的 WEB 网站的 http 服务一般都用短链接，因为长连接对于服务端来说会耗费一定的资源来让套接字保持存活。</p></li><li><p>对于中大型 WEB 网站一般都采用长连接，好处是响应用户请求的时间更短，用户体验更好，虽然更耗硬件资源一些，但这都不是事儿。另外，数据库的连接用长连接，如果用短连接频繁的通信会造成 socket 错误。</p></li></ol>',11),n=[t];function c(o,s){return e(),l("div",null,n)}const _=i(r,[["render",c],["__file","网络通信-长连接与短连接-97529371.html.vue"]]);export{_ as default};
